import{_ as a,o as t,c as n,a2 as s}from"./chunks/framework.B72_uj9U.js";const m=JSON.parse('{"title":"DeerFlow Benchmarks and Reception","description":"","frontmatter":{"title":"DeerFlow Benchmarks and Reception","status":"complete"},"headers":[],"relativePath":"research/agents/deer-flow/benchmarks.md","filePath":"research/agents/deer-flow/benchmarks.md"}'),r={name:"research/agents/deer-flow/benchmarks.md"};function o(i,e,d,c,l,h){return t(),n("div",null,[...e[0]||(e[0]=[s(`<h1 id="deerflow-benchmarks-and-reception" tabindex="-1">DeerFlow Benchmarks and Reception <a class="header-anchor" href="#deerflow-benchmarks-and-reception" aria-label="Permalink to &quot;DeerFlow Benchmarks and Reception&quot;">​</a></h1><h2 id="traditional-benchmarks" tabindex="-1">Traditional Benchmarks <a class="header-anchor" href="#traditional-benchmarks" aria-label="Permalink to &quot;Traditional Benchmarks&quot;">​</a></h2><p>DeerFlow is <strong>not evaluated on traditional coding benchmarks</strong> (SWE-bench, Terminal-Bench, HumanEval, MBPP) because:</p><ol><li>It is not primarily a coding agent — it is a general-purpose super agent harness</li><li>Its performance is model-dependent: it acts as an orchestration layer over any configured LLM</li><li>Its value is in multi-step, long-horizon tasks (research, synthesis, content generation) not captured by coding benchmarks</li></ol><p><strong>For coding tasks specifically</strong>, DeerFlow&#39;s performance is bounded by the underlying model and the quality of the relevant skill specifications. ByteDance recommends Doubao-Seed-2.0-Code for coding tasks.</p><hr><h2 id="community-reception-v2-launch-february-2026" tabindex="-1">Community Reception (v2 Launch, February 2026) <a class="header-anchor" href="#community-reception-v2-launch-february-2026" aria-label="Permalink to &quot;Community Reception (v2 Launch, February 2026)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Metric</th><th>Value</th></tr></thead><tbody><tr><td>GitHub Trending rank</td><td><strong>#1 globally</strong> (Feb 28, 2026)</td></tr><tr><td>Trendshift ranking</td><td><strong>#1</strong> repositories chart</td></tr><tr><td>Launch catalyst</td><td>v2 release (ground-up rewrite from v1)</td></tr></tbody></table><p>DeerFlow&#39;s reception is notable because GitHub Trending #1 is typically achieved by viral developer tools, not AI agent harnesses. The launch day ranking reflects significant pent-up demand from the v1 user community, which had been extending the framework beyond its intended scope.</p><hr><h2 id="v1-→-v2-trajectory" tabindex="-1">v1 → v2 Trajectory <a class="header-anchor" href="#v1-→-v2-trajectory" aria-label="Permalink to &quot;v1 → v2 Trajectory&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Version</th><th>Architecture</th><th>Scope</th><th>Status</th></tr></thead><tbody><tr><td>v1 (1.x branch)</td><td>Monolithic deep-research framework</td><td>Deep web research + report generation</td><td>Maintained (legacy)</td></tr><tr><td>v2 (main branch)</td><td>Super agent harness on LangGraph</td><td>General-purpose: research, coding, slides, dashboards, pipelines</td><td>Active development</td></tr></tbody></table><p>The jump from v1 to v2 was a <strong>complete rewrite with no shared code</strong> — an unusual decision that signals how fundamentally the use case expanded. ByteDance documented the rationale explicitly: community developers had pushed v1 into territory it was never designed for, and v2 was designed to formalize what users were already doing.</p><hr><h2 id="recommended-models-bytedance-promoted" tabindex="-1">Recommended Models (ByteDance-Promoted) <a class="header-anchor" href="#recommended-models-bytedance-promoted" aria-label="Permalink to &quot;Recommended Models (ByteDance-Promoted)&quot;">​</a></h2><p>DeerFlow is model-agnostic but ByteDance highlights specific models for optimal performance:</p><table tabindex="0"><thead><tr><th>Model</th><th>Provider</th><th>Best For</th></tr></thead><tbody><tr><td>Doubao-Seed-2.0-Code</td><td>ByteDance Volcengine</td><td>Coding tasks (via Coding Plan)</td></tr><tr><td>DeepSeek v3.2</td><td>DeepSeek</td><td>General-purpose reasoning</td></tr><tr><td>Kimi 2.5</td><td>Moonshot</td><td>Long-context tasks</td></tr></tbody></table><p>Note: these are promotional recommendations from ByteDance&#39;s ecosystem partners. Any OpenAI-compatible endpoint works.</p><hr><h2 id="comparison-position-in-this-research" tabindex="-1">Comparison Position in This Research <a class="header-anchor" href="#comparison-position-in-this-research" aria-label="Permalink to &quot;Comparison Position in This Research&quot;">​</a></h2><p>Within the agent taxonomy used in this research:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>CLI Coding Agents (Terminal-Bench focus)</span></span>
<span class="line"><span>    ForgeCode (81.8%) ← #1 Terminal-Bench 2.0</span></span>
<span class="line"><span>    Claude Code (58%)</span></span>
<span class="line"><span>    Codex CLI</span></span>
<span class="line"><span>    ...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>General Coding + Research Agents</span></span>
<span class="line"><span>    OpenHands (event-driven, broader task scope)</span></span>
<span class="line"><span>    DeerFlow ← here (research-first, coding capable)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Deep Research + Synthesis Agents</span></span>
<span class="line"><span>    DeerFlow v1 (retired) ← narrow research scope</span></span></code></pre></div><p>DeerFlow v2 sits between general-purpose coding agents and dedicated research tools — the &quot;super agent harness&quot; framing is accurate in that it intentionally spans both categories.</p><hr><h2 id="qualitative-signals" tabindex="-1">Qualitative Signals <a class="header-anchor" href="#qualitative-signals" aria-label="Permalink to &quot;Qualitative Signals&quot;">​</a></h2><ul><li>Community extended v1 beyond its design scope (data pipelines, dashboards, slide decks) — indicating strong fit-to-need</li><li>ByteDance committed to a ground-up rewrite rather than patching v1 — indicating organizational investment</li><li>#1 GitHub Trending on launch day — indicating broad developer awareness</li><li>Active contributions from external contributors (not just ByteDance employees) — indicating healthy open-source ecosystem</li></ul>`,26)])])}const u=a(r,[["render",o]]);export{m as __pageData,u as default};
